Smart enumerations are a design pattern used in Domain-Driven Design (DDD) to represent a set of distinct values that have a specific meaning within a particular context. Here's an example of how to implement smart enumerations in C#:

```csharp
public enum Color
{
    // Values are not just a simple list, they have a specific meaning
    // Each value has a description and a set of behaviors associated with it
    Red,
    Green,
    Blue
}

public static class ColorExtensions
{
    // Each value has a description
    public static string Description(this Color color)
    {
        return color switch
        {
            Color.Red => "Red",
            Color.Green => "Green",
            Color.Blue => "Blue",
            _ => throw new ArgumentException("Invalid color")
        };
    }

    // Each value has a set of behaviors associated with it
    public static bool IsPrimary(this Color color)
    {
        return color switch
        {
            Color.Red or Color.Blue => true,
            _ => false
        };
    }

    public static bool IsSecondary(this Color color)
    {
        return color switch
        {
            Color.Green => true,
            _ => false
        };
    }
}

