import os
import pickle

class IndexCache:
    def __init__(self, cache_dir):
        self.cache_dir = cache_dir
        os.makedirs(self.cache_dir, exist_ok=True)

    def get_cache_path(self, index_file):
        return os.path.join(self.cache_dir, f"{os.path.basename(index_file)}.cache")

    def get(self, index_file):
        cache_path = self.get_cache_path(index_file)
        if os.path.exists(cache_path):
            with open(cache_path, "rb") as f:
                return pickle.load(f)
        return None

    def set(self, index_file, value):
        cache_path = self.get_cache_path(index_file)
        with open(cache_path, "wb") as f:
            pickle.dump(value, f)

    def delete(self, index_file):
        cache_path = self.get_cache_path(index_file)
        if os.path.exists(cache_path):
            os.remove(cache_path)
