```csharp
public abstract class BaseRepository<TEntity> : IRepository<TEntity> where TEntity : class
{
    protected readonly DbContext _dbContext;
    protected readonly DbSet<TEntity> _dbSet;

    public BaseRepository(DbContext dbContext)
    {
        _dbContext = dbContext;
        _dbSet = _dbContext.Set<TEntity>();
    }

    public virtual async Task<TEntity> GetByIdAsync(object id)
    {
        return await _dbSet.FindAsync(id);
    }

    public virtual async Task<TEntity> GetByDynamicAsync(string field, object value)
    {
        return await _dbSet
            .Where(x => GetDynamicExpression(field, x).Equals(value))
            .FirstOrDefaultAsync();
    }

    protected virtual Expression<Func<TEntity, bool>> GetDynamicExpression(string field, TEntity entity)
    {
        var parameter = Expression.Parameter(typeof(TEntity));
        var memberExpression = Expression.PropertyOrField(parameter, field);
        var constantExpression = Expression.Constant(value);
        var lambdaExpression = Expression.Lambda<Func<TEntity, bool>>(
            Expression.Equal(memberExpression, constantExpression),
            parameter);
        return lambdaExpression;
    }

